impl From<AuthConfig> for kreuzcrawl::AuthConfig {
    fn from(val: AuthConfig) -> Self {
        match val.r#type.as_str() {
            "basic" => Self::Basic {
                username: val.username.clone().unwrap_or_default(),
                password: val.password.clone().unwrap_or_default(),
            },
            "bearer" => Self::Bearer {
                token: val.token.clone().unwrap_or_default(),
            },
            "header" => Self::Header {
                name: val.name.clone().unwrap_or_default(),
                value: val.value.clone().unwrap_or_default(),
            },
            _ => Self::Basic {
                username: Default::default(),
                password: Default::default(),
            },
        }
    }
}

impl From<kreuzcrawl::AuthConfig> for AuthConfig {
    fn from(val: kreuzcrawl::AuthConfig) -> Self {
        match val {
            kreuzcrawl::AuthConfig::Basic { username, password } => Self {
                r#type: "basic".to_string(),
                name: None,
                password: Some(password),
                token: None,
                username: Some(username),
                value: None,
            },
            kreuzcrawl::AuthConfig::Bearer { token } => Self {
                r#type: "bearer".to_string(),
                name: None,
                password: None,
                token: Some(token),
                username: None,
                value: None,
            },
            kreuzcrawl::AuthConfig::Header { name, value } => Self {
                r#type: "header".to_string(),
                name: Some(name),
                password: None,
                token: None,
                username: None,
                value: Some(value),
            },
        }
    }
}

